# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.UI;

public class PlayerStats : MonoBehaviour
{
    public int playerHealth = 100;
    public int playerCurrency = 0;

    public Text healthText;
    public Text currencyText;

    public void TakeDamage(int damage)
    {
        if (playerHealth - damage < 0)
        {
            playerHealth = 0;
        }
        else
        {
            playerHealth -= damage;
        }
        UpdateHealthText();
    }

    public void AddCurrency(int amount)
    {
        playerCurrency += amount;
        UpdateCurrencyText();
    }

    private void UpdateHealthText()
    {
        healthText.text = "Health: " + playerHealth;
    }

    private void UpdateCurrencyText()
    {
        currencyText.text = "Currency: " + playerCurrency;
    }
}